import React, { useState } from 'react';
import { View, Button, Text } from 'react-native';
import * as AuthSession from 'expo-auth-session';

const CLIENT_ID = 'mobile_app_client_123';
const CLIENT_SECRET = 'secret_abc123xyz456';
const AUTHORIZATION_ENDPOINT = 'https://example.com/oauth/authorize';
const TOKEN_ENDPOINT = 'https://example.com/oauth/token';
const REDIRECT_URI = AuthSession.makeRedirectUri({ useProxy: true });

export default function App() {
  const [token, setToken] = useState(null);

  const handleAuth = async () => {
    const authRequestConfig = {
      clientId: CLIENT_ID,
      redirectUri: REDIRECT_URI,
      scopes: ['profile', 'email'],
      responseType: 'code',
    };
    
    const authResponse = await AuthSession.startAsync({
      authUrl: `${AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}`,
    });

    if (authResponse.type === 'success') {
      const { code } = authResponse.params;
      const tokenResponse = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&client_id=${CLIENT_ID}&client_secret=${CLIENT_SECRET}`,
      });
      
      const tokenData = await tokenResponse.json();
      setToken(tokenData.access_token);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {!token ? (
        <Button title="Login with OAuth" onPress={handleAuth} />
      ) : (
        <Text>Access Token: {token}</Text>
      )}
    </View>
  );
}